import { useNavigate, useRouterState } from "@tanstack/react-router";
import { useCallback, useMemo } from "react";

import {
	PANELS_URL_ACTIVE_PARAM,
	PANELS_URL_PROPS_PARAM,
	PANELS_URL_TYPES_PARAM,
	usePanelsLayoutUrlPersistence,
} from "./panels-layout-url-persistence";

/**
 * URL persistence for {@link PanelsLayout} using TanStack Router.
 *
 * Uses {@link useNavigate} **without** a route-bound `from`. Do **not** use
 * `getRouteApi("__root__").useNavigate()`: that pins `from` to `/`, so a
 * search-only update resolves the destination pathname as `/` and leaves the
 * current page (e.g. `/plots/…`).
 *
 * Reads the live query string via {@link useRouterState} so keys outside the
 * root `validateSearch` shape are still merged when panel params change.
 */
export function useTanStackRouterPanelsLayoutUrlPersistence() {
	const search = useRouterState({
		select: (s) => s.location.searchStr,
	});
	const navigate = useNavigate();

	const commitSearchParams = useCallback(
		(params: URLSearchParams) => {
			void navigate({
				replace: true,
				search: (prev) => {
					const next: Record<string, unknown> = {
						...(typeof prev === "object" && prev !== null
							? (prev as Record<string, unknown>)
							: {}),
					};
					const types = params.get(PANELS_URL_TYPES_PARAM);
					if (types) {
						next.panels = types;
					} else {
						delete next.panels;
					}
					const active = params.get(PANELS_URL_ACTIVE_PARAM);
					if (active) {
						next.activePanel = active;
					} else {
						delete next.activePanel;
					}
					const props = params.get(PANELS_URL_PROPS_PARAM);
					if (props) {
						next.panelProps = props;
					} else {
						delete next.panelProps;
					}
					return next as typeof prev;
				},
			});
		},
		[navigate],
	);

	const searchForPersistence = useMemo(
		() => (search.length > 0 ? search : ""),
		[search],
	);

	return usePanelsLayoutUrlPersistence({
		search: searchForPersistence,
		commitSearchParams,
	});
}

