import type { ReactNode } from "react";
import { ChevronRight } from "lucide-react";

import { cn } from "@/lib/utils";

export type AppBreadcrumbCrumb = { label: string; href?: string };

export type AppBreadcrumbsProps = {
	items: readonly AppBreadcrumbCrumb[];
	className?: string;
	/** Optional link renderer (e.g. TanStack Router `Link`) for crumbs with `href`. */
	LinkComponent?: React.ComponentType<{
		to: string;
		className?: string;
		children: ReactNode;
	}>;
};

export function AppBreadcrumbs({
	items,
	className,
	LinkComponent,
}: AppBreadcrumbsProps) {
	return (
		<nav aria-label="Breadcrumb" className={cn("flex flex-wrap items-center gap-1", className)}>
			{items.map((item, i) => {
				const last = i === items.length - 1;
				return (
					<span key={`${item.label}-${i}`} className="inline-flex items-center gap-1">
						{i > 0 ? (
							<ChevronRight
								className="size-3.5 shrink-0 text-muted-foreground"
								aria-hidden
							/>
						) : null}
						{item.href && !last ? (
							LinkComponent ? (
								<LinkComponent
									to={item.href}
									className="text-[0.65rem] font-bold uppercase tracking-widest text-muted-foreground underline-offset-4 hover:text-foreground"
								>
									{item.label}
								</LinkComponent>
							) : (
								<a
									href={item.href}
									className="text-[0.65rem] font-bold uppercase tracking-widest text-muted-foreground underline-offset-4 hover:text-foreground"
								>
									{item.label}
								</a>
							)
						) : (
							<span
								className={cn(
									"text-[0.65rem] font-bold uppercase tracking-widest",
									last ? "text-foreground" : "text-muted-foreground",
								)}
							>
								{item.label}
							</span>
						)}
					</span>
				);
			})}
		</nav>
	);
}

import {
	type AppHeaderProps,
	type AppSidebarNavLinkComponent,
	type AppSidebarNavLinkProps,
	type AppSidebarProps,
	Button,
	Input,
	ManagementAppShell,
	ModeToggle,
	useSidebar,
} from "@portugal/ui";
import { Link, useRouterState } from "@tanstack/react-router";
import {
	type ForwardedRef,
	forwardRef,
	useCallback,
	useLayoutEffect,
	useMemo,
	useState,
} from "react";

import { AppPanelsLayout } from "#/panels/app-panels-layout";
import {
	breadcrumbTitleForPath,
	ESTATE_PRIMARY_NAV,
	ESTATE_SECONDARY_NAV,
	isPrimaryNavActive,
} from "#/shell/nav-config";
import { useAuth } from "../hooks/use-auth";

const RouterNavLink = forwardRef(function RouterNavLink(
	{
		to,
		className,
		children,
		onClick,
		"aria-current": ariaCurrent,
	}: AppSidebarNavLinkProps,
	ref: ForwardedRef<HTMLAnchorElement>,
) {
	return (
		<Link
			ref={ref}
			to={to}
			className={className}
			onClick={onClick}
			aria-current={ariaCurrent}
		>
			{children}
		</Link>
	);
}) as AppSidebarNavLinkComponent;

function CloseMobileSidebarOnRouteChange() {
	const pathname = useRouterState({ select: (s) => s.location.pathname });
	const { isMobile, setOpenMobile } = useSidebar();

	useLayoutEffect(() => {
		void pathname;
		if (isMobile) {
			setOpenMobile(false);
		}
	}, [pathname, isMobile, setOpenMobile]);

	return null;
}

/**
 * Application chrome: `@portugal/ui` {@link ManagementAppShell} + {@link AppPanelsLayout}.
 * Composes sidebar, header, and routed `children` without an extra wrapper shell.
 */
export function AppLayout({ children }: { children: React.ReactNode }) {
	const pathname = useRouterState({ select: (s) => s.location.pathname });
	const { activeRole, activeUser, loginWithToken, logout } = useAuth();
	const [tokenInput, setTokenInput] = useState("");
	const [authMessage, setAuthMessage] = useState("");

	const onLogin = useCallback(() => {
		if (loginWithToken(tokenInput)) {
			setAuthMessage("");
			setTokenInput("");
		} else {
			setAuthMessage("Invalid token");
		}
	}, [loginWithToken, tokenInput]);

	const crumbTitle = breadcrumbTitleForPath(pathname);

	const sidebar: AppSidebarProps = useMemo(
		() => ({
			workspaces: [
				{
					id: "local",
					name: "Plot scoring",
					logo: (
						<div className="flex size-full items-center justify-center rounded-sm bg-primary/15 text-xs font-bold text-primary">
							PT
						</div>
					),
					plan: "Local workspace",
				},
			],
			activeWorkspaceId: "local",
			showSearch: false,
			stickyNav: false,
			navItems: ESTATE_PRIMARY_NAV.map((item) => ({
				title: item.title,
				url: item.url,
				icon: item.icon,
				isActive: isPrimaryNavActive(item.url, pathname),
			})),
			secondaryItems: ESTATE_SECONDARY_NAV.map((item) => ({
				title: item.title,
				url: item.url,
				icon: item.icon,
				isActive: isPrimaryNavActive(item.url, pathname),
			})),
			user: activeUser
				? { name: activeUser.name, email: `${activeUser.role} · signed in` }
				: undefined,
			NavLink: RouterNavLink,
		}),
		[activeUser, pathname],
	);

	const header: AppHeaderProps = useMemo(
		() => ({
			showNavigation: false,
			showSearch: true,
			breadcrumbs: [
				{ label: "Workspace", href: "/plots" },
				{ label: crumbTitle },
			],
			NavLink: RouterNavLink,
			toolbarEnd: (
				<div className="flex flex-wrap items-center justify-end gap-2">
					<ModeToggle />
					{activeUser ? null : (
						<div className="flex items-center gap-1">
							<Input
								variant="obsidian"
								value={tokenInput}
								onChange={(e) => setTokenInput(e.target.value)}
								placeholder="Token"
								className="h-8 w-28 text-xs"
							/>
							<Button
								type="button"
								variant="outline"
								size="sm"
								onClick={onLogin}
							>
								Log in
							</Button>
							{authMessage ? (
								<span className="text-xs text-destructive">{authMessage}</span>
							) : null}
						</div>
					)}
					<span className="hidden rounded-full bg-muted px-2 py-1 text-xs text-muted-foreground sm:inline">
						{activeRole}
					</span>
				</div>
			),
			user: activeUser
				? {
						name: activeUser.name,
						email: activeUser.name,
						role: String(activeRole),
					}
				: undefined,
			onSignOut: activeUser ? () => logout() : undefined,
		}),
		[
			activeRole,
			activeUser,
			authMessage,
			crumbTitle,
			logout,
			onLogin,
			tokenInput,
		],
	);

	return (
		<AppPanelsLayout>
			<ManagementAppShell sidebar={sidebar} header={header}>
				<CloseMobileSidebarOnRouteChange />
				{children}
			</ManagementAppShell>
		</AppPanelsLayout>
	);
}

