function isCorruptedStringSpreadObject(o: Record<string, unknown>): boolean {
  const keys = Object.keys(o);
  return keys.length > 0 && keys.every((k) => /^\d+$/.test(k));
}

/**
 * Parse the raw `panelProps` query value (JSON map of panel type → props).
 * Unwraps TanStack Router’s default search serializer double-`JSON.stringify` on strings.
 *
 * @see https://github.com/TanStack/router/blob/main/packages/router-core/src/searchParams.ts — `stringifyValue` re-stringifies parseable strings.
 */
export function parsePanelPropsParamValue(propsString: string): Record<string, SerializableProps> {
  try {
    let parsed: unknown = JSON.parse(propsString);
    if (typeof parsed === 'string') {
      parsed = JSON.parse(parsed);
    }
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
      return {};
    }
    const map = parsed as Record<string, unknown>;
    if (isCorruptedStringSpreadObject(map)) {
      return {};
    }
    return map as Record<string, SerializableProps>;
  } catch (error) {
    console.error('Error parsing panel props from URL query', error);
    return {};
  }
}

/**
 * Normalize `panelProps` after TanStack’s `defaultParseSearch` (values are JSON-parsed once).
 * Keeps an **object** shape for validated search so `defaultStringifySearch` does not double-encode.
 */
export function normalizePanelPropsFromSearch(raw: unknown): Record<string, SerializableProps> | undefined {
  if (raw === undefined || raw === null) {
    return undefined;
  }
  if (typeof raw === 'string') {
    const map = parsePanelPropsParamValue(raw);
    return Object.keys(map).length > 0 ? map : undefined;
  }
  if (typeof raw === 'object' && !Array.isArray(raw)) {
    const rec = raw as Record<string, unknown>;
    if (isCorruptedStringSpreadObject(rec)) {
      return undefined;
    }
    return rec as Record<string, SerializableProps>;
  }
  return undefined;
}

